code = """import json
import pandas as pd

# Load the orders data
orders = locals()['var_functions.query_db:6']
order_items = locals()['var_functions.query_db:8']

# Convert to DataFrames
df_orders = pd.DataFrame(orders)
df_order_items = pd.DataFrame(order_items)

# Clean data: remove leading # and trailing whitespace from Id fields
clean_id = lambda x: str(x).replace('#', '').strip() if x else x

# Apply cleaning to relevant columns
df_orders['Id'] = df_orders['Id'].apply(clean_id)
df_orders['OwnerId'] = df_orders['OwnerId'].apply(clean_id)

df_order_items['OrderId'] = df_order_items['OrderId'].apply(clean_id)

# Convert numeric fields
df_order_items['Quantity'] = pd.to_numeric(df_order_items['Quantity'])
df_order_items['UnitPrice'] = pd.to_numeric(df_order_items['UnitPrice'])

# Merge orders with order items
df_merged = pd.merge(df_orders, df_order_items, left_on='Id', right_on='OrderId', how='inner')

# Calculate sales amount for each order item
df_merged['SalesAmount'] = df_merged['Quantity'] * df_merged['UnitPrice']

# Group by OwnerId (agent) and sum sales
df_agent_sales = df_merged.groupby('OwnerId')['SalesAmount'].sum().reset_index()

# Find agent with top sales
top_agent = df_agent_sales.loc[df_agent_sales['SalesAmount'].idxmax()]

top_agent_id = top_agent['OwnerId']
top_agent_sales = top_agent['SalesAmount']

result = {
    'top_agent_id': top_agent_id,
    'total_sales': top_agent_sales
}

print('__RESULT__:')
print(json.dumps(result))"""

